const order = $input.first().json.order;
if (!order) return [];

const serviceLabel = order.type_service === 'click_collect' ? 'Click & Collect' : 'Livraison';
const dateFormatted = order.created_at
  ? new Date(order.created_at).toLocaleString('fr-FR', {
      day: '2-digit', month: 'long', year: 'numeric',
      hour: '2-digit', minute: '2-digit',
    })
  : '';

const rows = (order.items || []).map(function(item) {
  var qte = Number(item.quantity) || 1;
  var pu = Number(item.price) || 0;
  var total = (pu * qte).toFixed(2).replace('.', ',');
  var puStr = pu.toFixed(2).replace('.', ',');
  var custom = (item.customizations && item.customizations.length)
    ? '<br><small style="color:#888">' + item.customizations.join(', ') + '</small>' : '';
  return '<tr>'
    + '<td>' + item.name + custom + '</td>'
    + '<td style="text-align:center">' + qte + '</td>'
    + '<td style="text-align:right">' + puStr + ' €</td>'
    + '<td style="text-align:right;font-weight:600">' + total + ' €</td>'
    + '</tr>';
}).join('');

var addr = (order.type_service === 'delivery' && order.delivery_address)
  ? order.delivery_address : '—';

var notesHtml = order.notes
  ? '<div style="background:#fffbf5;border-left:3px solid #f97316;padding:10px 14px;margin-bottom:24px;font-size:13px"><strong>Notes :</strong> ' + order.notes + '</div>'
  : '';

var css = '* { margin:0; padding:0; box-sizing:border-box; } body { font-family:Arial,sans-serif; color:#333; padding:40px; font-size:14px; } .logo { text-align:center; margin-bottom:12px; } .logo img { width:100px; height:100px; object-fit:contain; } h1 { font-size:26px; font-weight:900; color:#111; text-align:center; margin-bottom:8px; } .sub { text-align:center; color:#666; font-size:13px; margin-bottom:8px; } hr.sep { border:none; border-top:3px solid #f97316; margin:20px 0; } .ttl { text-align:center; background:#f9f9f9; border:1px solid #eee; padding:14px; border-radius:8px; margin-bottom:24px; } .ttl h2 { font-size:18px; font-weight:900; letter-spacing:2px; } .grid { display:grid; grid-template-columns:1fr 1fr; gap:16px; margin-bottom:24px; } .box { border:1px solid #eee; border-radius:8px; padding:16px; } .box h3 { color:#f97316; font-size:11px; text-transform:uppercase; letter-spacing:1px; margin-bottom:10px; font-weight:700; } .row { display:flex; justify-content:space-between; margin-bottom:6px; font-size:12px; } .row strong { color:#555; } table { width:100%; border-collapse:collapse; margin-bottom:20px; font-size:13px; } thead tr { border-bottom:2px solid #f97316; } th { padding:10px 8px; text-align:left; font-size:11px; text-transform:uppercase; color:#666; font-weight:600; } tbody tr { border-bottom:1px solid #f0f0f0; } td { padding:10px 8px; } .tot { text-align:right; margin-bottom:24px; } .tot-box { display:inline-block; border:2px solid #f97316; border-radius:8px; padding:12px 24px; } .tot-lbl { font-size:11px; font-weight:700; color:#f97316; letter-spacing:1px; } .tot-amt { font-size:26px; font-weight:900; color:#111; } .footer { border-top:1px solid #eee; padding-top:16px; text-align:center; color:#999; font-size:11px; }';

var html = '<!DOCTYPE html><html lang="fr"><head><meta charset="UTF-8"><style>' + css + '</style></head><body>'
  + '<div class="logo"><img src="https://pizzadalcielo.com/images/logo.png" alt="Pizza dal Cielo"></div>'
  + '<h1>Pizza dal Cielo</h1>'
  + '<p class="sub">Fort-de-France, Martinique<br>Tél : +596 696 88 72 70 | contact@pizzadalcielo.com</p>'
  + '<hr class="sep">'
  + '<div class="ttl"><h2>REÇU CLIENT</h2></div>'
  + '<div class="grid">'
  + '<div class="box"><h3>Détails commande</h3>'
  + '<div class="row"><strong>N° Cde :</strong><span>' + order.id.slice(0,8).toUpperCase() + '</span></div>'
  + '<div class="row"><strong>Date :</strong><span>' + dateFormatted + '</span></div>'
  + '<div class="row"><strong>Heure :</strong><span>' + (order.heure_souhaitee || '—') + '</span></div>'
  + '<div class="row"><strong>Service :</strong><span>' + serviceLabel + '</span></div>'
  + '<div class="row"><strong>Statut :</strong><span>' + order.status + '</span></div>'
  + '</div>'
  + '<div class="box"><h3>Client</h3>'
  + '<div class="row"><strong>Nom :</strong><span>' + (order.client_name || '') + '</span></div>'
  + '<div class="row"><strong>Tél :</strong><span>' + (order.client_phone || '') + '</span></div>'
  + '<div class="row"><strong>Adresse :</strong><span>' + addr + '</span></div>'
  + '</div>'
  + '</div>'
  + '<table><thead><tr>'
  + '<th>Article</th>'
  + '<th style="text-align:center">Qté</th>'
  + '<th style="text-align:right">P.U.</th>'
  + '<th style="text-align:right">Total</th>'
  + '</tr></thead><tbody>' + rows + '</tbody></table>'
  + '<div class="tot"><div class="tot-box">'
  + '<div class="tot-lbl">PAYÉ</div>'
  + '<div class="tot-amt">' + order.total.toFixed(2).replace('.', ',') + ' €</div>'
  + '</div></div>'
  + notesHtml
  + '<div class="footer"><p>Merci de votre visite ! À bientôt chez Pizza dal Cielo.</p></div>'
  + '</body></html>';

return [{
  json: {
    CLIENT_NAME: order.client_name || '',
    CLIENT_EMAIL: order.client_email || '',
    ORDER_ID: order.id.slice(0, 8).toUpperCase(),
    DATE: dateFormatted,
    TOTAL: order.total.toFixed(2).replace('.', ',') + ' €',
    PHONE: order.client_phone || '',
    SERVICE: serviceLabel,
    HEURE: order.heure_souhaitee || '—',
    STATUT: order.status,
    html: html,
    order: order,
  }
}];
